import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function screenForCompliance(chainName, walletAddress) {
  const txns = await client.TransactionService.getTransactionsForAddressV3(
    chainName, walletAddress, { pageSize: 100 }
  );
  // Flag interactions with known high-risk protocols (example: Tornado Cash)
  const FLAGGED = ["0x722122df12d4e14e13ac3b6895a86e84145b6967"]; // example
  const riskyTxns = (txns.data?.items ?? []).filter(tx =>
    FLAGGED.includes(tx.to_address?.toLowerCase()) ||
    FLAGGED.includes(tx.from_address?.toLowerCase())
  );
  return { walletAddress, compliancePass: riskyTxns.length === 0, flaggedTxns: riskyTxns.length };
}
